sql:
SELECT method_name
FROM teaching_methods
WHERE is_in_class = 1;

SELECT COUNT(*) AS in_class_method_count
FROM teaching_methods
WHERE is_in_class = 1;

SELECT COUNT(*) AS practice_count
FROM teaching_practices
WHERE method_id = 0;

external_knowledge:
- Top three teaching methods refer to the methods with the highest average scores and the highest total number of students benefited; 
- Average score is the average of the scores given by the students for a particular teaching method; 
- Total number of students benefited refers to the total number of students who have been taught using a particular method; 
- Faculties refer to the teachers or instructors who use the teaching methods.

sql:
SELECT user_name
FROM faculties
ORDER BY user_name;

SELECT SUM(student_count) AS total_students
FROM resource_usage
WHERE resource_id = 1;

SELECT method_name
FROM teaching_methods
WHERE last_updated = (SELECT MAX(last_updated) FROM teaching_methods);

SELECT COUNT(*) AS faculty_count
FROM faculties
WHERE department = 'Law School';

SELECT engagement_type, SUM(student_count) AS total_students
FROM student_engagement
GROUP BY engagement_type;

SELECT resource_name, accessibility
FROM external_resources
WHERE type = 'CALI Lesson';

SELECT AVG(score) AS average_score
FROM teaching_evaluations
WHERE user_id = 1;
